const i=[{id:"psychoanalysis",name:"精神分析",nameEn:"PSYCHOANALYSIS",period:"1890s — 至今",subtitle:"探索无意识的深海",description:"人的行为并非完全由理性驱动。在我们能察觉的意识之下，涌动着欲望、创伤和被压抑的记忆——它们才是真正的导演。",accent:"#6B5B95",icon:"◎",figures:["freud","jung","adler","erikson"],concepts:["unconscious","defense-mechanisms","shadow","collective-unconscious","id-ego-superego","oedipus-complex","psychosexual-stages","transference","repression","projection","denial","rationalization","sublimation","individuation"],experiments:["dream-analysis","free-association","case-studies"]},{id:"behaviorism",name:"行为主义",nameEn:"BEHAVIORISM",period:"1910s — 1970s",subtitle:"行为是环境的回声",description:"不必猜测内心在想什么——只看行为本身。刺激与反应之间的规律，足以解释人为什么做他们做的事。",accent:"#D4A843",icon:"⬡",figures:["pavlov","skinner","watson"],concepts:["conditioning","reinforcement","operant-conditioning","stimulus-response","shaping","extinction"],experiments:["pavlov-dog","skinner-box","little-albert"]},{id:"humanistic",name:"人本主义",nameEn:"HUMANISTIC",period:"1950s — 至今",subtitle:"每个人都有自我实现的力量",description:"人不是机器，也不是症状的集合。每个人都有向善、成长和实现自身潜能的内在动力——心理学的任务是帮助它绽放。",accent:"#5B9A6F",icon:"✿",figures:["maslow","rogers","frankl"],concepts:["self-actualization","hierarchy-of-needs","unconditional-regard","peak-experience","meaning-of-life","congruence"],experiments:["maslow-hierarchy","rogers-therapy","frankl-logotherapy"]},{id:"cognitive",name:"认知心理学",nameEn:"COGNITIVE PSYCHOLOGY",period:"1960s — 至今",subtitle:"思维的捷径与陷阱",description:"大脑是一台精密但不完美的信息处理器。它用捷径快速做出判断——而这些捷径，常常让我们犯错却不自知。",accent:"#4A90A4",icon:"◇",figures:["kahneman","tversky","piaget","beck"],concepts:["cognitive-bias","confirmation-bias","anchoring","heuristics","memory","attention","dual-process","loss-aversion"],experiments:["invisible-gorilla","kahneman-prospect","false-memory","stroop-effect"]},{id:"developmental",name:"发展心理学",nameEn:"DEVELOPMENTAL",period:"1900s — 至今",subtitle:"从摇篮到暮年的人生地图",description:"人的一生是一条不断变化的河流。从婴儿期的第一次依恋，到青春期的身份探索，再到老年的回顾与和解——每个阶段都有独特的课题。",accent:"#C47D4E",icon:"△",figures:["piaget","erikson","bowlby","vygotsky"],concepts:["attachment-theory","cognitive-stages","psychosocial-stages","zone-of-proximal","object-permanence","identity-crisis","scaffolding","secure-base"],experiments:["strange-situation","piaget-conservation","marshmallow-test"]},{id:"social",name:"社会心理学",nameEn:"SOCIAL PSYCHOLOGY",period:"1930s — 至今",subtitle:"他人如何塑造你的行为",description:"你以为自己是独立的个体？研究表明：群体的力量远超想象。从服从权威到旁观者效应，社会情境在悄悄操控你的选择。",accent:"#B85C5C",icon:"○",figures:["milgram","zimbardo","asch","festinger"],concepts:["conformity","obedience","bystander-effect","groupthink","cognitive-dissonance","attribution","prejudice","social-facilitation"],experiments:["milgram-obedience","stanford-prison","asch-conformity","bystander-smoke"]}],a=[{id:"freud",name:"西格蒙德·弗洛伊德",nameEn:"Sigmund Freud",years:"1856 — 1939",school:"psychoanalysis",quote:"未被表达的情绪永远不会消失。它们只是被活埋了，并将在未来以更加丑陋的方式涌现。",contribution:"创立精神分析学派，提出无意识理论、人格结构（本我/自我/超我）、心理防御机制等核心概念。",works:["梦的解析 (1899)","精神分析引论 (1916)","自我与本我 (1923)"],theories:["无意识理论","人格结构（本我/自我/超我）","性心理发展阶段","心理防御机制","俄狄浦斯情结"]},{id:"jung",name:"卡尔·荣格",nameEn:"Carl Jung",years:"1875 — 1961",school:"psychoanalysis",quote:"知道自己的黑暗，是最好的应对他人黑暗的方法。",contribution:"提出集体无意识、原型理论、阴影自我和个体化概念。从弗洛伊德的精神分析中发展出分析心理学。",works:["红书 (1914)","心理类型 (1921)","原型与集体无意识 (1959)"],theories:["集体无意识","原型理论","阴影自我","个体化","内外倾"]},{id:"adler",name:"阿尔弗雷德·阿德勒",nameEn:"Alfred Adler",years:"1870 — 1937",school:"psychoanalysis",quote:"人所有的烦恼，都来自人际关系。",contribution:"提出自卑与补偿理论、社会兴趣概念，创立个体心理学。是第一个与弗洛伊德分道扬镳的精神分析学家。",works:["理解人性 (1927)","自卑与超越 (1932)","个体心理学的实践与理论 (1920)"],theories:["自卑与补偿","社会兴趣","个体心理学","生活风格"]},{id:"erikson",name:"埃里克·埃里克森",nameEn:"Erik Erikson",years:"1902 — 1994",school:"psychoanalysis",quote:"人生最大的任务是在各个发展阶段中找到平衡——在获得中不失去自我，在失去中找到新的意义。",contribution:"提出心理社会发展八阶段理论，强调终身发展和社会文化因素对人格形成的影响。",works:["童年与社会 (1950)","同一性：青少年与危机 (1968)","生命历史与历史时刻 (1975)"],theories:["心理社会发展八阶段","同一性危机","终身发展观"]},{id:"pavlov",name:"伊万·巴甫洛夫",nameEn:"Ivan Pavlov",years:"1849 — 1936",school:"behaviorism",quote:"科学要求人献出毕生的精力，即使你只有两次生命，也还是不够的。",contribution:"发现经典条件反射——通过反复配对刺激，可以使生物体对中性刺激产生条件反应。这一发现奠定了行为主义的基础。",works:["条件反射演讲集 (1928)","高级神经活动客观研究 (1927)"],theories:["经典条件反射","条件刺激与无条件刺激","消退与泛化"]},{id:"skinner",name:"B.F. 斯金纳",nameEn:"B.F. Skinner",years:"1904 — 1990",school:"behaviorism",quote:"自由是一种幻觉。我们的行为是由环境塑造的——认识到这一点，才是真正的自由。",contribution:"提出操作性条件反射和强化理论，发明斯金纳箱。他认为行为是由其后果塑造的——奖励强化行为，惩罚削弱行为。",works:["沃尔登第二 (1948)","科学与人类行为 (1953)","超越自由与尊严 (1971)"],theories:["操作性条件反射","强化理论","程序教学","行为塑造"]},{id:"watson",name:"约翰·华生",nameEn:"John B. Watson",years:"1878 — 1958",school:"behaviorism",quote:"给我一打健康的婴儿，我可以把他们训练成任何类型的专家——医生、律师、艺术家、商人，甚至乞丐和小偷。",contribution:'行为主义的创始人，主张心理学应只研究可观察的行为，拒绝内省法。著名的"小阿尔伯特实验"证明了恐惧可以通过条件反射习得。',works:["行为主义者眼中的心理学 (1919)","行为主义 (1924)"],theories:["行为主义","环境决定论","情绪条件化"]},{id:"maslow",name:"亚伯拉罕·马斯洛",nameEn:"Abraham Maslow",years:"1908 — 1970",school:"humanistic",quote:"如果你唯一的工具是锤子，你就会把所有问题都看成钉子。",contribution:"提出需求层次理论——从生理需求到自我实现，人的动机是有层次的。他是人本主义心理学的先驱之一。",works:["动机与人格 (1954)","存在心理学探索 (1968)","人性能达的境界 (1971)"],theories:["需求层次理论","自我实现","高峰体验","元动机"]},{id:"rogers",name:"卡尔·罗杰斯",nameEn:"Carl Rogers",years:"1902 — 1987",school:"humanistic",quote:"当一个人被接纳为他自己时，他就开始改变。",contribution:"创立以人为中心的治疗方法，强调无条件积极关注、真诚一致和共情。他认为每个人都有自我实现的内在倾向。",works:["当事人中心治疗 (1951)","论人的成长 (1961)","自由学习 (1969)"],theories:["以人为中心疗法","无条件积极关注","真诚一致","共情"]},{id:"frankl",name:"维克多·弗兰克尔",nameEn:"Viktor Frankl",years:"1905 — 1997",school:"humanistic",quote:"人可以被夺走一切，除了一样东西——选择自己态度的自由。",contribution:'创立意义疗法（Logotherapy），提出"意义的意志"是人类最根本的驱力。他是纳粹集中营的幸存者，将苦难转化为对生命意义的深刻思考。',works:["活出意义来 (1946)","意义疗法与存在分析 (1946)","医生与灵魂 (1948)"],theories:["意义疗法","意义的意志","存在的真空","矛盾意向法"]},{id:"kahneman",name:"丹尼尔·卡尼曼",nameEn:"Daniel Kahneman",years:"1934 — 2024",school:"cognitive",quote:"我们对自己认为熟知的事物确信无疑，但我们对自己的无知却一无所知。",contribution:"提出双系统理论（快思考与慢思考）和前景理论，揭示了人类决策中的系统性偏差。2002年获得诺贝尔经济学奖。",works:["思考，快与慢 (2011)","不确定状况下的判断 (1982)"],theories:["双系统理论（系统1/系统2）","前景理论","损失厌恶","锚定效应"]},{id:"tversky",name:"阿莫斯·特沃斯基",nameEn:"Amos Tversky",years:"1937 — 1996",school:"cognitive",quote:"人们不是风险厌恶的——他们是损失厌恶的。",contribution:"与卡尼曼合作创立行为经济学，提出前景理论和多种认知偏差理论。他的工作改变了人们对理性决策的理解。",works:["判断中的启发式与偏差 (1974)","前景理论 (1979)"],theories:["前景理论","代表性启发式","可得性启发式","框架效应"]},{id:"piaget",name:"让·皮亚杰",nameEn:"Jean Piaget",years:"1896 — 1980",school:"cognitive",quote:"儿童不是微缩版的成人——他们有自己独特的思维方式。",contribution:"提出认知发展四阶段理论，揭示了儿童思维如何从感觉运动阶段逐步发展到形式运算阶段。是发展认知心理学的奠基人。",works:["儿童的语言与思维 (1923)","儿童心理学 (1966)","发生认识论 (1970)"],theories:["认知发展四阶段","图式/同化/顺应","客体永久性","守恒概念"]},{id:"beck",name:"阿伦·贝克",nameEn:"Aaron Beck",years:"1921 — 2021",school:"cognitive",quote:"人们不是被事物本身所困扰，而是被他们对事物的看法所困扰。",contribution:"创立认知行为疗法（CBT），提出认知三角理论（对自己、世界和未来的负面信念维持着抑郁）。CBT 是目前最有效的心理治疗之一。",works:["抑郁症：原因与治疗 (1967)","认知疗法与情绪障碍 (1979)","焦虑症与恐惧症 (1985)"],theories:["认知行为疗法（CBT）","认知三角","自动思维","认知扭曲"]},{id:"bowlby",name:"约翰·鲍尔比",nameEn:"John Bowlby",years:"1907 — 1990",school:"developmental",quote:"人类从摇篮到坟墓，最幸福的时刻莫过于将情感寄托在某个值得信赖的人身上。",contribution:"提出依恋理论——婴儿与照料者之间的早期关系模式，会深刻影响其一生的人际关系和情感调节能力。",works:["依恋与失落三部曲 (1969-1980)","儿童照料与爱的成长 (1953)"],theories:["依恋理论","安全基地","内部工作模式","分离焦虑"]},{id:"vygotsky",name:"列夫·维果茨基",nameEn:"Lev Vygotsky",years:"1896 — 1934",school:"developmental",quote:"学习领先于发展。儿童在合作中能做到的，超过了他们独自能做到的。",contribution:"提出社会文化理论和最近发展区（ZPD）概念。他强调社会互动和文化工具在认知发展中的核心作用。",works:["思维与语言 (1934)","心理发展理论 (1930-1934)"],theories:["社会文化理论","最近发展区（ZPD）","脚手架教学","内化"]},{id:"milgram",name:"斯坦利·米尔格拉姆",nameEn:"Stanley Milgram",years:"1933 — 1984",school:"social",quote:"普通人在接到权威的命令时，会做出令人难以置信的残忍行为——不是因为他们邪恶，而是因为他们服从。",contribution:"设计了著名的服从权威实验，揭示了普通人在权威指令下会做出违背良心的行为。这一发现深刻改变了人们对道德和服从的理解。",works:["服从权威 (1974)","城市里的生活 (1970)"],theories:["服从权威理论","代理状态","渐近式承诺"]},{id:"zimbardo",name:"菲利普·津巴多",nameEn:"Philip Zimbardo",years:"1933 — 2024",school:"social",quote:"不是坏苹果的问题——是坏苹果桶的问题。",contribution:'主导了斯坦福监狱实验，证明情境和系统力量可以彻底改变正常人的行为。提出"英雄想象"概念，鼓励人们抵抗不良情境的力量。',works:["路西法效应 (2007)","心理学与生活 (多版)"],theories:["去个性化","情境力量","英雄想象","时间透视理论"]},{id:"asch",name:"所罗门·阿希",nameEn:"Solomon Asch",years:"1907 — 1996",school:"social",quote:"独立不是不与他人相处，而是在群体压力下保持自己的判断。",contribution:"设计了从众实验，证明人们会在明显错误的情况下随大流。约75%的参与者至少一次给出了与群体一致的错误答案。",works:["社会心理学 (1952)","格式塔心理学思想 (1946)"],theories:["从众效应","信息性社会影响","规范性社会影响"]},{id:"festinger",name:"利昂·费斯廷格",nameEn:"Leon Festinger",years:"1919 — 1989",school:"social",quote:"人有维持内部一致性的强烈驱力。当信念与行为冲突时，人会改变信念而非行为。",contribution:"提出认知失调理论——当人的信念与行为不一致时，会经历心理不适，并通过改变信念来恢复平衡。这是社会心理学最具影响力的理论之一。",works:["认知失调理论 (1957)","当预言失灵时 (1956)"],theories:["认知失调理论","社会比较理论","非正式社会传播"]}],o=[{id:"unconscious",name:"无意识",nameEn:"THE UNCONSCIOUS",school:"psychoanalysis",description:"冰山之下，占据心灵最大部分的是我们无法直接察觉的领域——无意识。它储存着被压抑的欲望、遗忘的记忆和原始的冲动，却时刻影响着我们的行为、情绪和梦境。",example:'你有没有过这样的经历：明明已经"忘记"了一件事，但某个气味、声音或场景突然让它涌上心头？这就是无意识在说话。'},{id:"defense-mechanisms",name:"心理防御机制",nameEn:"DEFENSE MECHANISMS",school:"psychoanalysis",description:"当现实太痛苦、焦虑太强烈时，大脑会自动启动保护程序——否认、压抑、投射、合理化……它们让你暂时感觉好一点，但代价是看不见真相。",example:'"我不生气"——但你的拳头已经握紧了。否认是最原始的防御，它让危险"不存在"。'},{id:"shadow",name:"阴影",nameEn:"THE SHADOW",school:"psychoanalysis",description:'荣格提出的概念：每个人都有一个"阴影自我"——由被压抑、不被社会接受的特质组成。你最讨厌别人身上的东西，往往就是你阴影的投射。',example:'极度反感别人的"自私"？也许你从未允许自己"自私"过。'},{id:"collective-unconscious",name:"集体无意识",nameEn:"COLLECTIVE UNCONSCIOUS",school:"psychoanalysis",description:"荣格认为，除了个人无意识，人类还共享一层更深的心智结构——集体无意识。它包含全人类共有的原型：英雄、母亲、智慧老人、 Trickster……这些原型出现在全世界的神话和梦境中。",example:'为什么全世界不同文化的神话里，都有"英雄之旅"的故事？荣格说：因为英雄原型深植于我们的集体无意识中。'},{id:"conditioning",name:"条件反射",nameEn:"CONDITIONING",school:"behaviorism",description:'巴甫洛夫发现：通过反复配对，一个原本无关的刺激可以引发特定的反应。铃声本身不会让狗流口水——但当铃声反复与食物同时出现，狗学会了"铃声=食物"。',example:'为什么听到手机震动会心跳加速？因为你的大脑已经把"震动"和"可能有重要消息"联系在了一起。'},{id:"reinforcement",name:"强化",nameEn:"REINFORCEMENT",school:"behaviorism",description:"斯金纳提出：行为的频率取决于它的后果。被奖励的行为会增加（正强化），被惩罚的行为会减少。这个简单原理解释了从学习习惯到成瘾行为的广泛现象。",example:'为什么社交媒体让人上瘾？每一次点赞、评论都是一次"正强化"——你的大脑记住了"发帖=奖励"。'},{id:"self-actualization",name:"自我实现",nameEn:"SELF-ACTUALIZATION",school:"humanistic",description:'马斯洛需求层次的顶端：当所有基础需求被满足后，人会追求成为"自己能够成为的一切"——发挥潜能、追求意义、体验美。这不是奢侈品，而是人性的基本驱力。',example:"一个画家必须画画，一个作家必须写作——不是因为外部要求，而是因为内在冲动。这就是自我实现。"},{id:"hierarchy-of-needs",name:"需求层次",nameEn:"HIERARCHY OF NEEDS",school:"humanistic",description:"马斯洛将人类需求分为五层：生理需求 → 安全需求 → 爱与归属 → 尊重 → 自我实现。低层需求未满足时，人很难追求高层需求——但也有例外。",example:"饿着肚子的人很难思考人生意义——但不代表他们没有这个需求。"},{id:"unconditional-regard",name:"无条件积极关注",nameEn:"UNCONDITIONAL POSITIVE REGARD",school:"humanistic",description:"罗杰斯提出：当一个人被无条件地接纳和尊重时——不因成绩、行为或外貌而改变——他才敢于展现真实的自己，并开始真正的成长。",example:'"当你知道无论说什么都不会被否定时，你才开始说真话。"'},{id:"cognitive-bias",name:"认知偏差",nameEn:"COGNITIVE BIASES",school:"cognitive",description:'大脑使用"捷径"（启发式）快速做出判断，但这些捷径系统性地产出错误。确认偏误、锚定效应、可得性偏差……我们比想象中更不理性。',example:'你买了一件 2000 元的外套觉得"很划算"——但如果你之前看到的是 5000 元的，这个"划算"只是锚定效应。'},{id:"confirmation-bias",name:"确认偏误",nameEn:"CONFIRMATION BIAS",school:"cognitive",description:"人们倾向于寻找、解释和记忆那些支持自己已有信念的信息，同时忽略或贬低反驳性证据。你并非在寻找真相——你只是在寻找支持自己的证据。",example:'相信"星座很准"的人只会注意到"准"的时候，而忽略所有不准的时候。'},{id:"anchoring",name:"锚定效应",nameEn:"ANCHORING EFFECT",school:"cognitive",description:'人在做判断时，会过度依赖最先接收到的信息——即使这个信息完全随机。第一个数字会成为"锚"，拉着你往它的方向偏。',example:'为什么商品要标"原价 999，现价 299"？因为 999 就是那个锚。有了它，299 才显得"便宜"。'},{id:"cognitive-dissonance",name:"认知失调",nameEn:"COGNITIVE DISSONANCE",school:"social",description:"当你的信念和行为发生冲突时，你会感到心理上的不适。为了消除这种不适，大多数人不会改变行为——而是改变自己的信念来合理化行为。",example:'"我明知道该早睡，但又在刷手机……算了，偶尔一次没关系。"——这就是认知失调被消除的瞬间。'},{id:"conformity",name:"从众",nameEn:"CONFORMITY",school:"social",description:"阿希实验证明：即使答案明显错误，约75%的人会至少一次跟随群体的选择。不是因为他们看不清——而是因为与群体不一致带来的压力太大了。",example:"所有人都站起来鼓掌，你不知道为什么，但你也站了起来。"},{id:"obedience",name:"服从权威",nameEn:"OBEDIENCE TO AUTHORITY",school:"social",description:'米尔格拉姆实验揭示：普通人在权威指令下，会做出违背良心的行为。实验中 65% 的参与者在实验者要求下，对他人施加了"致命"电击。',example:'"我只是执行命令"——这句话在历史上反复出现，而米尔格拉姆证明了它适用于绝大多数人。'},{id:"bystander-effect",name:"旁观者效应",nameEn:"BYSTANDER EFFECT",school:"social",description:'人在群体中更不容易伸出援手——不是因为冷漠，而是因为"责任分散"：人越多，每个人都觉得"总会有人管的"。',example:"路边有人摔倒，路过的人越多，越没人停下来帮忙。这不是人心冷漠——这是心理机制。"},{id:"attachment-theory",name:"依恋理论",nameEn:"ATTACHMENT THEORY",school:"developmental",description:'鲍尔比提出：婴儿与照料者之间的早期互动模式，会形成"依恋类型"——安全型、焦虑型、回避型。这个模式会延续到成年后的亲密关系中。',example:"为什么有些人在恋爱中总是害怕被抛弃？可能追溯到婴儿期与照料者的互动模式。"},{id:"cognitive-stages",name:"认知发展阶段",nameEn:"COGNITIVE DEVELOPMENT STAGES",school:"developmental",description:'皮亚杰发现：儿童的思维不是"小号成人思维"，而是经历了四个质变阶段——从感觉运动到前运算到具体运算再到形式运算。每个阶段都有独特的认知特点。',example:'给3岁孩子看同一杯水倒进高瘦杯子里，他会说"水变多了"——因为他还不懂"守恒"。'},{id:"psychosocial-stages",name:"心理社会八阶段",nameEn:"PSYCHOSOCIAL STAGES",school:"developmental",description:'埃里克森提出：人的一生经历八个心理社会危机——从婴儿期的"信任vs不信任"到老年的"整合vs绝望"。每个阶段都有独特的发展课题。',example:'青春期的核心危机是"身份认同 vs 角色混淆"——这也是为什么青少年总在问"我是谁"。'},{id:"groupthink",name:"群体思维",nameEn:"GROUPTHINK",school:"social",description:'当群体追求一致性和凝聚力时，可能会做出灾难性的决策。成员压抑异议，自我审查，创造出"我们是一致的"幻觉。',example:'会议室里所有人都点头说"同意"，但每个人心里都觉得不对劲——这就是群体思维在运作。'},{id:"id-ego-superego",name:"本我·自我·超我",nameEn:"ID, EGO, SUPEREGO",school:"psychoanalysis",description:"弗洛伊德将人格分为三层：本我（Id）是原始欲望的源泉，遵循快乐原则；自我（Ego）是现实的中介者，遵循现实原则；超我（Superego）是内化的道德标准，追求完美。三者之间的冲突，构成了人格动力学的核心。",example:"深夜你想吃蛋糕（本我），但你知道它在减肥计划之外（超我），于是你决定只吃一小口（自我的妥协）。"},{id:"oedipus-complex",name:"俄狄浦斯情结",nameEn:"OEDIPUS COMPLEX",school:"psychoanalysis",description:"弗洛伊德认为，3-6岁的儿童会对异性父母产生亲密渴望，对同性父母产生嫉妒和敌意。成功解决这一冲突是健康人格发展的关键。",example:'"我长大要和妈妈结婚"——一个4岁男孩说出的话，弗洛伊德认为这是俄狄浦斯情结的自然表达。'},{id:"psychosexual-stages",name:"性心理发展阶段",nameEn:"PSYCHOSEXUAL STAGES",school:"psychoanalysis",description:"弗洛伊德提出人格发展经历五个阶段：口唇期、肛门期、性器期、潜伏期和生殖期。如果在某个阶段固着，会影响成年后的性格特征。",example:"成年后的咬指甲、吸烟等习惯，可能是口唇期固着的表现。"},{id:"transference",name:"移情",nameEn:"TRANSFERENCE",school:"psychoanalysis",description:"在治疗关系中，来访者会无意识地将对重要他人的情感和期待投射到治疗师身上。它是理解来访者内心世界的珍贵窗口。",example:"来访者突然对治疗师产生强烈愤怒或依恋——这不是针对治疗师本人，而是早期关系模式的重演。"},{id:"repression",name:"压抑",nameEn:"REPRESSION",school:"psychoanalysis",description:"最基本的防御机制：将痛苦的记忆、欲望推入无意识。被压抑的内容不会消失——它以焦虑、症状或梦境的形式回来。",example:"完全不记得6岁前的一次手术，但每到医院就莫名心慌——被压抑的记忆通过身体在说话。"},{id:"projection",name:"投射",nameEn:"PROJECTION",school:"psychoanalysis",description:'将自己无法接受的冲动或特质归因于他人。你真诚地相信"别人就是这样"，但实际上你看到的是自己的倒影。',example:"总是怀疑伴侣出轨的人，可能自己在压抑对他人暧昧的冲动。"},{id:"denial",name:"否认",nameEn:"DENIAL",school:"psychoanalysis",description:"面对痛苦的现实时，最原始的防御是否认它的存在。它让人暂时安全，但也让人与现实脱节。",example:'被诊断重病后说"一定是搞错了"——否认在保护你，让你有时间缓冲。'},{id:"rationalization",name:"合理化",nameEn:"RATIONALIZATION",school:"psychoanalysis",description:'为自己的行为编造"合理的"解释，掩盖真正的动机。合理化让你觉得自己是理性的——但真正的理由藏在无意识中。',example:'"我不是因为害怕才放弃，是因为时机不对"——合理化让失败变得可以接受。'},{id:"sublimation",name:"升华",nameEn:"SUBLIMATION",school:"psychoanalysis",description:"最成熟的防御机制：将不可接受的冲动转化为社会认可的活动。攻击性变成运动竞技，性冲动变成艺术创作。",example:"充满攻击性的人成为出色的外科医生——手术刀成了攻击冲动的合法出口。"},{id:"individuation",name:"个体化",nameEn:"INDIVIDUATION",school:"psychoanalysis",description:'荣格提出的终极发展目标：整合意识与无意识、光明与阴影，成为完整的自己。个体化不是变得"更好"，而是变得"更完整"。',example:"中年危机不一定是坏事——荣格认为它是灵魂在呼唤你开始个体化的旅程。"},{id:"operant-conditioning",name:"操作性条件反射",nameEn:"OPERANT CONDITIONING",school:"behaviorism",description:"斯金纳的核心理论：行为的频率由其后果决定。奖励增加行为频率，惩罚减少行为频率。关键在于后果——而非前因。",example:"孩子撒泼打滚就能得到糖果？他们学会了：撒泼=奖励。这就是操作性条件反射。"},{id:"stimulus-response",name:"刺激-反应",nameEn:"STIMULUS-RESPONSE (S-R)",school:"behaviorism",description:"行为主义的基本单元：特定刺激引发特定反应。理解了刺激-反应链条，就理解了行为。",example:'广告逻辑：将产品（刺激）与快乐/成功（反应）反复配对，让你"自动"想买。'},{id:"shaping",name:"行为塑造",nameEn:"SHAPING",school:"behaviorism",description:"通过逐步奖励越来越接近目标行为的过程，来训练复杂行为。",example:"教孩子学写字不是等完美才表扬，而是每次进步一点就鼓励——这就是行为塑造。"},{id:"extinction",name:"消退",nameEn:"EXTINCTION",school:"behaviorism",description:"当条件刺激不再伴随无条件刺激时，条件反应会逐渐减弱直至消失。",example:"不再回复伴侣的抱怨（去除强化），一段时间后抱怨频率下降——这就是消退。"},{id:"peak-experience",name:"高峰体验",nameEn:"PEAK EXPERIENCE",school:"humanistic",description:"马斯洛描述的极乐时刻：完全沉浸、自我消失、与世界合一。是自我实现者的标志性体验。",example:"听一首让你全身颤栗的音乐，看一场让你忘记呼吸的日落——那就是高峰体验。"},{id:"meaning-of-life",name:"生命意义",nameEn:"MEANING OF LIFE (Logos)",school:"humanistic",description:'弗兰克尔认为人最深的需求是"意义的意志"——寻找生命为什么值得活的答案。意义可以来自爱、创造、甚至苦难中的态度。',example:'在集中营里，能找到某种意义的人——哪怕只是"我要活着告诉世界发生了什么"——更可能活下来。'},{id:"congruence",name:"一致性",nameEn:"CONGRUENCE",school:"humanistic",description:'罗杰斯提出：当"理想自我"和"真实自我"一致时，人是心理健康的。成长的方向不是变成"更好的自己"，而是变成"更真实的自己"。',example:'你觉得自己"应该"开朗外向，但内心享受独处——这个裂缝就是不一致。'},{id:"heuristics",name:"启发式",nameEn:"HEURISTICS",school:"cognitive",description:"大脑用来快速判断的心理捷径。代表性启发式、可得性启发式、锚定启发式——捷径省时间，但系统性犯错。",example:'你觉得坐飞机比开车危险？因为空难新闻更"好记"——可得性启发式在欺骗你。'},{id:"memory",name:"记忆",nameEn:"MEMORY",school:"cognitive",description:"记忆不是录像带——每次回忆时重新构建。编码、存储、提取三个环节都可能出错。",example:'你"清楚地记得"911那天在做什么——但研究表明这些"闪光灯记忆"的准确率远低于人们以为的。'},{id:"attention",name:"注意力",nameEn:"ATTENTION",school:"cognitive",description:"注意力是心理资源的过滤器——你只能处理进入意识的一小部分信息。",example:'边开车边打电话，你可能"看到"了红灯但大脑没有"处理"——注意力的瓶颈比你想的更窄。'},{id:"dual-process",name:"双系统理论",nameEn:"DUAL PROCESS THEORY",school:"cognitive",description:"卡尼曼将思维分为系统1（快速、直觉）和系统2（缓慢、理性）。大部分时间在用系统1——够快，但经常出错。",example:'看到"2+2"不假思索就知道（系统1），但算"17×24"得停下来（系统2）。'},{id:"loss-aversion",name:"损失厌恶",nameEn:"LOSS AVERSION",school:"cognitive",description:"人对损失的敏感度约为等额收益的2倍。失去100元的痛苦远大于得到100元的快乐。",example:"投资者倾向于卖出盈利股票（锁定收益）而持有亏损股票（拒绝确认损失）——损失厌恶。"},{id:"attribution",name:"归因理论",nameEn:"ATTRIBUTION THEORY",school:"social",description:'基本归因错误：用性格解释别人的行为（"他脾气差"），用情境解释自己的行为（"我当时太累了"）。',example:'别人迟到="不靠谱"，你迟到="堵车了"。这就是基本归因错误。'},{id:"prejudice",name:"偏见",nameEn:"PREJUDICE",school:"social",description:"基于有限信息对群体的预先判断。可以是显性的或隐性的——即使是声称平等的人，也可能持有隐性偏见。",example:"完全相同的简历，用男性名字和女性名字——研究显示男性简历被认为更胜任。"},{id:"social-facilitation",name:"社会促进",nameEn:"SOCIAL FACILITATION",school:"social",description:"他人在场影响表现：简单任务中让你更好，复杂任务中让你更紧张。",example:"在观众面前弹熟练的曲子弹得更好，弹新学的曲子弹得更差。"},{id:"zone-of-proximal",name:"最近发展区",nameEn:"ZONE OF PROXIMAL DEVELOPMENT",school:"developmental",description:"维果茨基提出：儿童独立能达到的水平与在指导下能达到的水平之间的区域。好的教学就在这里。",example:"孩子自己能搭3层积木，在大人帮助下能搭7层——3到7层就是最近发展区。"},{id:"object-permanence",name:"客体永久性",nameEn:"OBJECT PERMANENCE",school:"developmental",description:'皮亚杰发现：约8个月前的婴儿认为"看不见的东西就不存在"。',example:'和婴儿玩"躲猫猫"为什么有趣？因为你每次"消失又出现"，对婴儿来说都是惊喜。'},{id:"identity-crisis",name:"同一性危机",nameEn:"IDENTITY CRISIS",school:"developmental",description:'埃里克森认为青春期的核心任务是建立"同一性"——回答"我是谁"。',example:'"我是谁？""我要成为什么样的人？"——青春期正常的发展任务。'},{id:"scaffolding",name:"脚手架教学",nameEn:"SCAFFOLDING",school:"developmental",description:"教师提供适当支持帮助学习者完成超出其独立能力的任务，随着能力提升逐步撤去。",example:"教孩子骑自行车——先扶着后座，等找到平衡了，悄悄松手。"},{id:"secure-base",name:"安全基地",nameEn:"SECURE BASE",school:"developmental",description:"鲍尔比提出：当婴儿知道照料者随时可提供安全时，才敢于探索世界。",example:'游乐场玩耍的孩子会时不时回头看父母——确认"安全基地"还在，然后继续探索。'}],s=[{id:"pavlov-dog",name:"巴甫洛夫的狗",nameEn:"Pavlov's Dogs",school:"behaviorism",year:1902,description:"巴甫洛夫在研究狗的消化系统时偶然发现：狗不仅在看到食物时流口水，在听到饲养员的脚步声时也会。他系统性地证明了：中性刺激（铃声）通过与无条件刺激（食物）反复配对，可以成为条件刺激，引发条件反应（流口水）。",significance:"奠定了经典条件反射理论的基础，深刻影响了行为主义和学习理论的发展。"},{id:"skinner-box",name:"斯金纳箱",nameEn:"Skinner's Box",school:"behaviorism",year:1938,description:'斯金纳设计了一个特殊的实验装置：按下杠杆，食物丸落入箱中。动物很快学会了"按杠杆=食物"。更关键的是，他发现奖励的"时间表"（每次奖励/间歇奖励）深刻影响了行为的持续性和消退速度。',significance:"揭示了操作性条件反射的原理——行为的后果（而非前因）决定了行为是否会被重复。"},{id:"little-albert",name:"小阿尔伯特实验",nameEn:"Little Albert Experiment",school:"behaviorism",year:1920,description:'华生让9个月大的婴儿"阿尔伯特"与一只白鼠玩耍，然后在他背后猛敲铁棒制造巨响。反复几次后，阿尔伯特不仅对白鼠产生恐惧，还将恐惧泛化到了兔子、狗甚至白色棉花球上。',significance:"证明了恐惧可以通过条件反射习得，并且可以泛化到相似的刺激上。这个实验因伦理问题至今备受争议。"},{id:"milgram-obedience",name:"米尔格拉姆服从实验",nameEn:"Milgram Obedience Experiment",school:"social",year:1963,description:'实验者要求参与者扮演"老师"，在"学生"（实验同谋）答错题时施加电击。电击强度从15V逐步增加到450V。尽管"学生"的惨叫声越来越强，但在实验者的催促下，65%的参与者一路加到了最高电压。',significance:"揭示了普通人在权威指令下的服从程度远超想象，深刻改变了人们对道德、责任和权威的理解。"},{id:"stanford-prison",name:"斯坦福监狱实验",nameEn:"Stanford Prison Experiment",school:"social",year:1971,description:'津巴多将普通大学生随机分为"囚犯"和"狱警"，在模拟监狱中生活。原本计划两周的实验在第六天被迫终止——"狱警"变得残暴专横，"囚犯"出现严重心理问题。所有人都忘记了这只是一个实验。',significance:'证明了情境和角色力量可以彻底改变正常人的行为。"不是坏苹果的问题——是坏苹果桶的问题。"'},{id:"asch-conformity",name:"阿希从众实验",nameEn:"Asch Conformity Experiment",school:"social",year:1951,description:'参与者被安排在一组"实验同谋"中间，被要求判断线段长度。当所有人都故意给出错误答案时，约75%的真实参与者至少一次跟随群体给出错误答案——即使正确答案一目了然。',significance:"揭示了社会压力对个体判断的强大影响。人们宁愿违背自己的感知，也不愿与群体不一致。"},{id:"bystander-smoke",name:"旁观者烟雾实验",nameEn:"Bystander Intervention Study",school:"social",year:1968,description:"被试者被安排在等候室填问卷。突然，烟雾从通风口涌入。当被试者独自一人时，75%会报告烟雾。但当房间里有其他（不动声色的实验同谋）人时，只有10%会报告。",significance:'证明了"责任分散"效应：在场的人越多，每个人感受到的责任越小，采取行动的可能性越低。'},{id:"strange-situation",name:"陌生情境实验",nameEn:"Strange Situation",school:"developmental",year:1969,description:"安斯沃思设计了一个标准化程序：让婴儿与母亲在陌生房间玩耍，然后母亲短暂离开，再回来。通过观察婴儿的反应，识别出三种依恋类型：安全型、焦虑-矛盾型和回避型。",significance:"将鲍尔比的依恋理论实证化，揭示了早期亲子关系对个体发展的深远影响。"},{id:"marshmallow-test",name:"棉花糖实验",nameEn:"The Marshmallow Test",school:"developmental",year:1972,description:"给4岁儿童一颗棉花糖：现在吃可以吃一颗，如果等15分钟可以吃两颗。后续追踪发现：能等待的孩子在学业成绩、社交能力和压力管理方面表现更好。",significance:"揭示了延迟满足能力与长期成功之间的关联。但也引发了关于意志力、环境和阶层因素的深入讨论。"},{id:"invisible-gorilla",name:"看不见的大猩猩",nameEn:"The Invisible Gorilla",school:"cognitive",year:1999,description:"参与者被要求观看一段篮球传球视频并数传球次数。视频中途，一个穿着大猩猩服装的人走进画面，捶胸，然后离开。大约一半的参与者完全没有注意到——因为他们正专注于数传球。",significance:'证明了"无意视盲"的存在：当注意力集中在某个任务上时，人会完全忽略眼前显而易见的事物。'},{id:"false-memory",name:"虚假记忆实验",nameEn:"False Memory Study",school:"cognitive",year:1995,description:'洛夫特斯向参与者展示他们童年时的照片，其中一张被PS成了热气球飞行场景。经过几次访谈后，约50%的参与者"回忆"起了这次从未发生过的热气球飞行，甚至补充了细节。',significance:"证明了记忆不是录像回放——它是可以被植入、篡改和重构的。这对司法证词和创伤记忆的讨论产生了深远影响。"},{id:"stroop-effect",name:"斯特鲁普效应",nameEn:"The Stroop Effect",school:"cognitive",year:1935,description:'当"红色"这个词被用蓝色墨水打印时，说出墨水的颜色（蓝色）变得困难——因为大脑自动读取了词义（红色），二者产生了冲突。这种干扰被称为斯特鲁普效应。',significance:"揭示了自动加工（阅读）和控制加工（颜色命名）之间的冲突，是认知心理学最经典的实验范式之一。"},{id:"kahneman-prospect",name:"前景理论实验",nameEn:"Prospect Theory",school:"cognitive",year:1979,description:"卡尼曼和特沃斯基发现：人在面对收益时倾向于规避风险（选确定的500元而不是50%概率的1000元），但在面对损失时倾向于冒险（选50%概率亏1000元而不是确定的亏500元）。",significance:'推翻了传统经济学的"理性人"假设，揭示了损失厌恶和心理账户等核心现象。卡尼曼因此获诺贝尔经济学奖。'}];function c(e){return i.find(n=>n.id===e)}function t(e){return o.find(n=>n.id===e)}export{t as a,o as c,s as e,a as f,c as g,i as s};
